    const deadline = Date.now() + timeoutMs;

    while (turns < maxTurns && Date.now() < deadline) {
      turns++;
      updateTask(delegate.id, { turns, lastOutput: output.slice(-200) || undefined });
      broadcastSSE(delegate.id, { type: "status", status: "running", turns });
      const promptText = turns === 1 ? prompt : "[系統] 繼續執行，完成後在回覆中說明結果。";

      const result = await Promise.race([
        inst.client.prompt(promptText),
        new Promise<never>((_, reject) =>
          setTimeout(() => reject(new Error("timeout")), Math.max(1000, deadline - Date.now())),
        ),
      ]);

      lastStopReason = result.stopReason;
      // If agent stopped normally (end_turn), check if it needs more turns
      if (lastStopReason === "end_turn" || lastStopReason === "stop") break;
      // tool_use means agent is still working — loop for next turn
    }

    // Extract summary from output (last 2000 chars as summary)
    const summary = output.length > 2000 ? output.slice(-2000) : output || "(no output)";

    const status: ResultPayload["status"] =
      Date.now() >= deadline ? "timeout" : "done";

    completeTask(delegate.id, status, { lastOutput: summary.slice(0, 200) });
    broadcastSSE(delegate.id, { type: "status", status });

    // Persist transcript for /memorytoskill
    appendTranscript(target, "user", prompt).catch(() => {});
    appendTranscript(target, "assistant", output).catch(() => {});

    logEvent("specialist_done", { target, taskId: delegate.id, status, turns });
    return {
      payload: { id: delegate.id, status, summary },
      rawOutput: output,
    };
  } catch (err: any) {
    const msg = err.message ?? String(err);
    const failStatus = msg.includes("timeout") ? "timeout" : "failed";
    completeTask(delegate.id, failStatus, { error: msg.slice(0, 200) });
    broadcastSSE(delegate.id, { type: "status", status: failStatus });
    logEvent("specialist_done", { target, taskId: delegate.id, status: failStatus, error: msg.slice(0, 100) });
    return {
      payload: { id: delegate.id, status: "failed", summary: `Error: ${msg.slice(0, 500)}` },
      rawOutput: output,
    };
  } finally {
    inst.client.removeListener("update", updateHandler);
    inst.busy = false;
    closeInstance(target);
  }
}

