// 不開 sweep timer：get 時 lazy 過期、set 時淘汰最舊（Map 插入序 ≈ 時間序），
// 過期後點舊按鈕走 index.ts 既有的 key fallback（與 bridge 重啟同路徑）。
const ASK_TTL_MS = 24 * 60 * 60 * 1000;
const ASK_MAX_ENTRIES = 500;

class AskRegistry {
  private m = new Map<number, { entries: AskEntry[]; at: number }>();
  set(messageId: number, entries: AskEntry[]): void {
    this.m.delete(messageId);
    while (this.m.size >= ASK_MAX_ENTRIES) {
      const oldest = this.m.keys().next().value;
      if (oldest === undefined) break;
      this.m.delete(oldest);
    }
    this.m.set(messageId, { entries, at: Date.now() });
  }
  get(messageId: number): AskEntry[] | undefined {
    const v = this.m.get(messageId);
    if (!v) return undefined;
    if (Date.now() - v.at > ASK_TTL_MS) {
      this.m.delete(messageId);
      return undefined;
    }
    return v.entries;
  }
  delete(messageId: number): void {
    this.m.delete(messageId);
  }
}

export const askRegistry = new AskRegistry();

