      stdio: ["pipe", "pipe", "pipe"],
      shell: true,
    });
  } else {
    this.proc = spawn(opts.command, opts.args, {
      cwd: opts.cwd,
      env: buildSpawnEnv(opts.env),
      stdio: ["pipe", "pipe", "pipe"],
    });
  }

  // Keep stdout as Buffer so LSP byte-length framing works correctly.
  this.proc.stderr.setEncoding("utf8");

  this.proc.stdout.on("data", (chunk: Buffer) => this.onStdout(chunk));
  this.proc.stderr.on("data", (chunk: string) => this.emit("stderr", chunk));
  this.proc.on("exit", (code) => {
    this.closed = true;
    for (const { reject } of this.pending.values()) {
      reject(new Error(`ACP agent exited with code ${code}`));
    }
    this.pending.clear();
    this.emit("exit", code);
  });
  this.proc.on("error", (err) => {
    this.emit("stderr", `spawn error: ${err.message}\n`);
  });
}

private onStdout(chunk: Buffer) {
  this.inBuf = this.inBuf.length === 0 ? chunk : Buffer.concat([this.inBuf, chunk]);
  // Keep draining: either LSP framed messages or newline-terminated JSON.
  for (;;) {
    const consumed = this.tryReadOne();
    if (!consumed) break;
  }
}

