async close() {
  if (this.closed) return;
  // 立即標記 closed 並 reject 所有 pending：即使 kill 沒生效（例如 pid
  // 已被回收重用），呼叫端的 session/prompt promise 也不會永久懸掛、
  // inflight 不會卡死。exit handler 之後到來時 pending 已空，清理冪等。
  this.closed = true;
  for (const { reject } of this.pending.values()) {
    reject(new Error("ACP agent closed"));
  }
  this.pending.clear();
  try {
    this.proc.stdin.end();
  } catch {
    /* noop */
  }
  // On Windows, proc.kill() only kills the direct child (e.g. cmd.exe),
  // leaving grandchildren (electron, long-running tools) alive as orphans.
  // Use taskkill /T to kill the entire process tree — async 版，避免
  // execSync 在多 session shutdown 時串行阻塞 event loop。
  if (process.platform === "win32" && this.proc.pid) {
    await new Promise<void>((resolve) => {
      execFile("taskkill", ["/T", "/F", "/PID", String(this.proc.pid)], () => {
        // taskkill 失敗（含 pid 已不存在）→ fallback 直接 kill 子進程
        if (this.proc.exitCode === null && !this.proc.killed) {
          try { this.proc.kill(); } catch { /* noop */ }
        }
        resolve();
      });
    });
  } else {
    this.proc.kill();
  }
}

