  const trimmed = text.replace(/[.\s…]+/g, "");
  if (!trimmed) {
    console.warn(`[relay] blocked empty/placeholder relay to "${targetBot}": "${text.slice(0, 40)}"`);
    return;
  }

  const transport = cfg.transport;
  let sent = false;

  // Telegram bot-to-bot transport
  if (transport === "telegram" || transport === "both") {
    const target = cfg.targetBotUsername;
    if (target) {
      try {
        const payload = `[RELAY:${cfg.botName}] ${text}`;
        await bot.api.sendMessage(target, payload);
        sent = true;
        console.log(`[relay] ✓ sent via TELEGRAM to ${target} (transport=${transport})`);
      } catch (err) {
        console.error(`[relay] telegram sendMessage to ${target} failed:`, err);
        if (transport === "both") console.log(`[relay] falling back to REDIS...`);
      }
    }
  }

  // Redis transport (primary or fallback)
  if (transport === "redis" || (transport === "both" && !sent)) {
    if (cfg.redisUrl && cfg.redisToken) {
      const msg: RelayMessage = { from: cfg.botName, text, ts: new Date().toISOString() };
      const key = redisKey(targetBot);
      await redisCommand(["LPUSH", key, JSON.stringify(msg)]);
      sent = true;
        console.log(`[relay] ✓ sent via REDIS to key "${key}" (transport=${transport})`);
    }
  }

  if (!sent) {
    console.error(`[relay] failed to send via any transport (transport=${transport})`);
    return;
  }

  if (transport === "redis" || transport === "both") ensurePollerRunning();

  const display = `📤 sent by ${cfg.botName} [${cfg.botName} -> ${targetBot}]\n${text}`;
  await bot.api.sendMessage(cfg.groupChatId, display).catch((err) =>
    console.error("[relay] group sendMessage failed:", err),
  );
}

/** Send a file to another bot via Telegram bot-to-bot (telegram/both transport only). */
export async function sendRelayFile(targetBot: string, filePath: string, caption: string = "[RELAY_INPUT]"): Promise<boolean> {
  if (!cfg || !bot) return false;
  if (process.env.RELAY_PAUSED === "true") {
    console.log(`[relay] RELAY_PAUSED — blocked outgoing file to "${targetBot}"`);
    return false;
  }
  if (targetBot === cfg.botName) {
    console.warn(`[relay] blocked self-send file (target="${targetBot}")`);
    return false;
  }
  const abs = path.resolve(filePath);
  if (!isUnderAllowedRoot(abs)) {
    console.warn(`[relay] blocked file outside allowed roots to "${targetBot}": ${abs}`);
    return false;
  }
  let st;
  try {
    st = await stat(abs);
  } catch (err) {
    console.warn(`[relay] sendRelayFile stat failed for ${abs}:`, (err as Error).message);
    return false;
  }
  if (!st.isFile()) {
    console.warn(`[relay] blocked non-file relay attachment to "${targetBot}": ${abs}`);
    return false;
  }
  const transport = cfg.transport;
  if (transport === "redis") {
    console.warn(`[relay] sendRelayFile requires telegram transport, current=${transport}`);
    return false;
  }
  const target = cfg.targetBotUsername;
  if (!target) {
    console.warn(`[relay] sendRelayFile: no targetBotUsername configured`);
    return false;
  }
  try {
    const ext = path.extname(abs).toLowerCase();
    // RELAY_OUTPUT with PNG: send as document to preserve transparency.
    // RELAY_INPUT: send as photo (compression OK for reference images).
    const isOutput = caption === "[RELAY_OUTPUT]";
    const asPhoto = IMG_EXT.has(ext) && st.size <= PHOTO_MAX_BYTES && !(isOutput && ext === ".png");
    if (asPhoto) {
      await bot.api.sendPhoto(target, new InputFile(abs), { caption });
    } else {
      await bot.api.sendDocument(target, new InputFile(abs), { caption });
    }
    console.log(`[relay] ✓ sent file via TELEGRAM to ${target}: ${abs}`);
    await bot.api.sendMessage(cfg.groupChatId, `📤🖼️ [${cfg.botName} -> ${targetBot}] file: ${abs}`).catch(() => {});
    return true;
  } catch (err) {
    console.error(`[relay] sendRelayFile to ${target} failed:`, err);
    return false;
  }
}

