272	          try { sizeBytes = (await stat(path.join(artifactsDir, f))).size; } catch { /* ignore */ }
273	          return { filename: f, taskId: m[2], slug: m[3], date: m[1], sizeBytes };
274	        }));
275	        json(res, entries);
