285	      json(res, result);
286	      return;
287	    }
288	
289	    // ─── Static files ────────────────────────────────────────────────────
290	    if (p === "/" || p === "/index.html") {
291	      try {
292	        const html = await readFile(path.join(staticDir, "index.html"), "utf8");
293	        res.writeHead(200, { "Content-Type": "text/html; charset=utf-8" });
294	        res.end(html);
295	      } catch {
296	        res.writeHead(500); res.end("index.html not found");
297	      }
298	      return;
299	    }
300	
301	    json(res, { error: "not found" }, 404);
302	    })().catch((err) => {
303	      console.error("[status-server] request error:", err);
304	      if (!res.headersSent) json(res, { error: "internal error" }, 500);
305	      else res.end();
306	    });
307	  });
308	
309	  // 預設只綁 loopback：API 會回 specialist 設定/preamble/facts，不該暴露到 LAN。
310	  // Tunnel（cloudflared/ngrok）連 localhost 即可；要 LAN 直連才設 STATUS_BIND_HOST。
311	  const host = process.env.STATUS_BIND_HOST?.trim() || "127.0.0.1";
312	  httpServer.listen(port, host, () => {
313	    console.log(`[status-server] listening on ${host}:${port}`);
314	  });
315	}
316	
317	export function stopStatusServer(): void {
318	  httpServer?.close();
319	  httpServer = undefined;
320	}
321	
322	// ─── SSE broadcast ─────────────────────────────────────────────────────────
323	
324	/** Broadcast an SSE event to all clients watching a task. */
325	export function broadcastSSE(taskId: string, data: Record<string, unknown>): void {
326	  const clients = sseClients.get(taskId);
327	  if (!clients || clients.size === 0) return;
328	  const payload = `data: ${JSON.stringify(data)}\n\n`;
329	  for (const res of clients) {
330	    res.write(payload);
331	  }
332	}
333	
334	function sseSend(res: ServerResponse, data: Record<string, unknown>): void {
335	  res.write(`data: ${JSON.stringify(data)}\n\n`);
336	}
337	
338	function json(res: ServerResponse, data: unknown, status = 200): void {
339	  res.writeHead(status, { "Content-Type": "application/json" });
340	  res.end(JSON.stringify(data));
341	}
