/**
 * Status Server — lightweight HTTP API + Mini App for /status monitoring.
 * Independent server on STATUS_PORT (default 3847).
 */
import { createServer, type Server, type IncomingMessage, type ServerResponse } from "node:http";
import { readFile, readdir, stat } from "node:fs/promises";
import path from "node:path";
import { listTasks, listActiveTasks, getTask, cancelTask } from "./status-store.js";
import { getSpecialists, type SpecialistEntry } from "./specialist.js";
import { getRecentEvents, type StateEvent } from "./event-log.js";
import { config } from "./config.js";

let httpServer: Server | undefined;

// SSE clients per taskId
const sseClients = new Map<string, Set<ServerResponse>>();

// ─── Specialist helpers ────────────────────────────────────────────────────

/** decodeURIComponent 對無效 percent-encoding（%zz）會 throw URIError，統一轉成 null 讓路由回 400。 */
function safeDecode(s: string): string | null {
  try { return decodeURIComponent(s); } catch { return null; }
}

function escapeRegex(s: string): string {
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

/** env 可能含 API key 等機密，回傳前把機密欄位遮罩。 */
function maskEnv(env?: Record<string, string>): Record<string, string> | undefined {
  if (!env) return env;
  return Object.fromEntries(Object.entries(env).map(([k, v]) =>
    [k, /key|token|secret|password|credential/i.test(k) ? "••••••" : v]));
}

function extractModel(entry: SpecialistEntry): string {
  const args = entry.harness.args;
  const idx = args.indexOf("--model");
  return idx >= 0 && idx + 1 < args.length ? args[idx + 1] : "default";
}

function countRecentTasks(name: string, events: StateEvent[], days: number): number {
  const cutoff = new Date();
  cutoff.setDate(cutoff.getDate() - days);
  const cutoffStr = cutoff.toISOString();
  return events.filter(
    (e) => e.type === "specialist_spawn" && e.ts >= cutoffStr &&
      ((e.payload.name as string) === name || (e.payload.target as string) === name)
  ).length;
}

let factsCache: { ts: number; data: Map<string, Array<{ id: string; timestamp: string; text: string }>> } | null = null;
const FACTS_CACHE_TTL = 60_000;

async function loadFactsForSpecialist(name: string): Promise<{ totalCount: number; recentFacts: Array<{ id: string; timestamp: string; text: string }> }> {
  const now = Date.now();
  if (!factsCache || now - factsCache.ts > FACTS_CACHE_TTL) {
    factsCache = { ts: now, data: new Map() };
    const userId = (process.env.ALLOWED_USER_IDS ?? "").split(",")[0]?.trim();
    if (userId) {
      const shardDir = path.join(config.memoryDir, "facts_Topic", userId);
      try {
        const files = await readdir(shardDir);
        for (const file of files) {
          if (!file.endsWith(".md")) continue;
          const content = await readFile(path.join(shardDir, file), "utf8");
          const lines = content.split("\n").filter((l) => l.startsWith("- ["));
          for (const line of lines) {
            // 行格式：- [f_xxx] [ISO timestamp] text（timestamp 可省略）
            const m = line.match(/^- \[([^\]]+)\](?:\s+\[([^\]]+)\])?\s+(.+)$/);
            if (!m) continue;
            const fact = { id: m[1], timestamp: m[2] ?? "", text: m[3] };
            for (const sp of getSpecialists()) {
              if (line.toLowerCase().includes(sp.name.toLowerCase())) {
                if (!factsCache.data.has(sp.name)) factsCache.data.set(sp.name, []);
                factsCache.data.get(sp.name)!.push(fact);
              }
            }
          }
        }
      } catch { /* shardDir may not exist */ }
    }
  }
  const facts = factsCache.data.get(name) ?? [];
  return { totalCount: facts.length, recentFacts: facts.slice(-5).reverse() };
}

export function startStatusServer(port: number): void {
  if (httpServer) return;

  const staticDir = path.resolve(import.meta.dirname ?? ".", "..", "status-app");

  // 前端一律以 location.origin 同源 fetch（localhost 直開 / Mini App tunnel 皆同源），
  // 不設 CORS header——避免任意網頁跨源讀取本機 API。
  httpServer = createServer((req, res) => {
    // 錯誤邊界：async body 任何 throw（如畸形 percent-encoding）只回 500，
    // 不能變成 unhandledRejection——index.ts 的全域 handler 會 process.exit(1) 殺掉整個 bridge。
    void (async () => {
    const url = new URL(req.url ?? "/", `http://localhost:${port}`);
    const p = url.pathname;

    // ─── API routes ──────────────────────────────────────────────────────
    if (p === "/api/status" && req.method === "GET") {
      const active = listActiveTasks();
      const recent = listTasks().filter((t) => t.status !== "running").slice(-10);
      json(res, { active, recent });
      return;
    }

    // SSE stream
    const streamMatch = p.match(/^\/api\/status\/([^/]+)\/stream$/);
    if (streamMatch && req.method === "GET") {
      const taskId = streamMatch[1];
      res.writeHead(200, {
        "Content-Type": "text/event-stream",
        "Cache-Control": "no-cache",
        "Connection": "keep-alive",
      });
      // Register client
      if (!sseClients.has(taskId)) sseClients.set(taskId, new Set());
      sseClients.get(taskId)!.add(res);
      // Send current status immediately
      const task = getTask(taskId);
      if (task) {
        sseSend(res, { type: "status", status: task.status, turns: task.turns });
      }
      req.on("close", () => {
        sseClients.get(taskId)?.delete(res);
        if (sseClients.get(taskId)?.size === 0) sseClients.delete(taskId);
      });
      return;
    }

    // Cancel
    const cancelMatch = p.match(/^\/api\/status\/([^/]+)\/cancel$/);
    if (cancelMatch && req.method === "POST") {
      const ok = cancelTask(cancelMatch[1]);
      if (!ok) json(res, { error: "cannot cancel" }, 400);
      else {
        broadcastSSE(cancelMatch[1], { type: "status", status: "cancelled" });
        json(res, { ok: true });
      }
      return;
    }

    // Single task
    const taskMatch = p.match(/^\/api\/status\/([^/]+)$/);
    if (taskMatch && req.method === "GET") {
      const task = getTask(taskMatch[1]);
      if (!task) json(res, { error: "not found" }, 404);
      else json(res, task);
      return;
    }

    // ─── Specialist API routes ─────────────────────────────────────────
    if (p === "/api/specialists" && req.method === "GET") {
      const specialists = getSpecialists();
      const active = listActiveTasks();
      const events = getRecentEvents(2000);
      const summaries = specialists.map((sp) => {
        const activeTask = active.find((t) => t.specialist === sp.name);
        return {
          name: sp.name,
          model: extractModel(sp),
          cwd: sp.cwd,
          maxTurns: sp.maxTurns ?? 15,
          timeoutMs: sp.timeoutMs ?? 1_800_000,
          mcpServers: (sp.mcpServers ?? []).filter((s: any) => !s.disabled).map((s: any) => s.name),
          status: activeTask ? "busy" as const : "idle" as const,
          activeTaskId: activeTask?.taskId,
          recentTaskCount: countRecentTasks(sp.name, events, 7),
        };
      });
      json(res, summaries);
      return;
    }

    const spDetailMatch = p.match(/^\/api\/specialists\/([^/]+)$/);
    if (spDetailMatch && req.method === "GET") {
      const name = safeDecode(spDetailMatch[1]);
      if (name === null) { json(res, { error: "bad name" }, 400); return; }
      const sp = getSpecialists().find((s) => s.name === name);
      if (!sp) { json(res, { error: "not found" }, 404); return; }
      const active = listActiveTasks();
      const events = getRecentEvents(2000);
      const activeTask = active.find((t) => t.specialist === sp.name);
      json(res, {
        name: sp.name,
        model: extractModel(sp),
        cwd: sp.cwd,
        maxTurns: sp.maxTurns ?? 15,
        timeoutMs: sp.timeoutMs ?? 1_800_000,
        mcpServers: (sp.mcpServers ?? []).filter((s: any) => !s.disabled).map((s: any) => s.name),
        status: activeTask ? "busy" : "idle",
        activeTaskId: activeTask?.taskId,
        recentTaskCount: countRecentTasks(sp.name, events, 7),
        harness: sp.harness,
        env: maskEnv(sp.env),
        mcpServersFull: (sp.mcpServers ?? []).filter((s: any) => !s.disabled).map((s: any) => ({
          name: s.name, command: s.command, url: s.url,
        })),
      });
      return;
    }

    const spPreambleMatch = p.match(/^\/api\/specialists\/([^/]+)\/preamble$/);
    if (spPreambleMatch && req.method === "GET") {
      const name = safeDecode(spPreambleMatch[1]);
      // 白名單擋 path traversal（%2E%2E%2F 解碼後可逃出 specialists 目錄）
      if (name === null || !getSpecialists().some((s) => s.name === name)) {
        json(res, { error: "not found" }, 404);
        return;
      }
      const bridgeDir = path.resolve(config.sessionCwd);
      const preamblePath = path.join(bridgeDir, "specialists", name, "preamble.md");
      try {
        const content = await readFile(preamblePath, "utf8");
        json(res, { content });
      } catch {
        json(res, { error: "preamble not found" }, 404);
      }
      return;
    }

    const spHistoryMatch = p.match(/^\/api\/specialists\/([^/]+)\/history$/);
    if (spHistoryMatch && req.method === "GET") {
      const name = safeDecode(spHistoryMatch[1]);
      if (name === null) { json(res, { error: "bad name" }, 400); return; }
      const events = getRecentEvents(2000);
      const spawns = new Map<string, StateEvent>();
      const history: Array<Record<string, unknown>> = [];
      for (const e of events) {
        if (e.type === "specialist_spawn" &&
            ((e.payload.name as string) === name || (e.payload.target as string) === name)) {
          const taskId = (e.payload.taskId as string) ?? (e.payload.instanceId as string) ?? e.ts;
          spawns.set(taskId, e);
        }
        if (e.type === "specialist_done" &&
            ((e.payload.target as string) === name || (e.payload.name as string) === name)) {
          const taskId = (e.payload.taskId as string) ?? "";
          const spawn = spawns.get(taskId);
          const startTime = spawn?.ts ?? e.ts;
          const endTime = e.ts;
          const elapsed = Math.round((new Date(endTime).getTime() - new Date(startTime).getTime()) / 1000);
          history.push({
            taskId,
            goal: (e.payload.goal as string) ?? (spawn?.payload.goal as string) ?? "",
            status: (e.payload.status as string) ?? (e.payload.error ? "failed" : "done"),
            startTime, endTime, elapsedSec: elapsed,
            turns: e.payload.turns, verifier: e.payload.verifier,
          });
        }
      }
      json(res, history.reverse().slice(0, 20));
      return;
    }

    const spArtifactsMatch = p.match(/^\/api\/specialists\/([^/]+)\/artifacts$/);
    if (spArtifactsMatch && req.method === "GET") {
      const name = safeDecode(spArtifactsMatch[1]);
      if (name === null) { json(res, { error: "bad name" }, 400); return; }
      const artifactsDir = path.join(config.memoryDir, "artifacts");
      try {
        const files = await readdir(artifactsDir);
        // 檔名格式 <date>_<taskId>_<specialist>_<slug>.json；taskId 本身可含底線
        // （如 pt_codegen_probe），positional split 會解錯，用 specialist name 錨定。
        const nameRe = new RegExp(`^(\\d{4}-\\d{2}-\\d{2})_(.+?)_${escapeRegex(name)}_(.+)\\.json$`);
        const matched = files.filter((f) => nameRe.test(f)).sort().reverse().slice(0, 20);
        const entries = await Promise.all(matched.map(async (f) => {
          const m = f.match(nameRe)!;
          let sizeBytes = 0;
          try { sizeBytes = (await stat(path.join(artifactsDir, f))).size; } catch { /* ignore */ }
          return { filename: f, taskId: m[2], slug: m[3], date: m[1], sizeBytes };
        }));
        json(res, entries);
      } catch { json(res, []); }
      return;
    }

    const spFactsMatch = p.match(/^\/api\/specialists\/([^/]+)\/facts$/);
    if (spFactsMatch && req.method === "GET") {
      const name = safeDecode(spFactsMatch[1]);
      if (name === null) { json(res, { error: "bad name" }, 400); return; }
      const result = await loadFactsForSpecialist(name);
      json(res, result);
      return;
    }

    // ─── Static files ────────────────────────────────────────────────────
    if (p === "/" || p === "/index.html") {
      try {
        const html = await readFile(path.join(staticDir, "index.html"), "utf8");
        res.writeHead(200, { "Content-Type": "text/html; charset=utf-8" });
        res.end(html);
      } catch {
        res.writeHead(500); res.end("index.html not found");
      }
      return;
    }

    json(res, { error: "not found" }, 404);
    })().catch((err) => {
      console.error("[status-server] request error:", err);
      if (!res.headersSent) json(res, { error: "internal error" }, 500);
      else res.end();
    });
  });

  // 預設只綁 loopback：API 會回 specialist 設定/preamble/facts，不該暴露到 LAN。
  // Tunnel（cloudflared/ngrok）連 localhost 即可；要 LAN 直連才設 STATUS_BIND_HOST。
  const host = process.env.STATUS_BIND_HOST?.trim() || "127.0.0.1";
  httpServer.listen(port, host, () => {
    console.log(`[status-server] listening on ${host}:${port}`);
  });
}

export function stopStatusServer(): void {
  httpServer?.close();
  httpServer = undefined;
}

// ─── SSE broadcast ─────────────────────────────────────────────────────────

/** Broadcast an SSE event to all clients watching a task. */
export function broadcastSSE(taskId: string, data: Record<string, unknown>): void {
  const clients = sseClients.get(taskId);
  if (!clients || clients.size === 0) return;
  const payload = `data: ${JSON.stringify(data)}\n\n`;
  for (const res of clients) {
    res.write(payload);
  }
}

function sseSend(res: ServerResponse, data: Record<string, unknown>): void {
  res.write(`data: ${JSON.stringify(data)}\n\n`);
}

function json(res: ServerResponse, data: unknown, status = 200): void {
  res.writeHead(status, { "Content-Type": "application/json" });
  res.end(JSON.stringify(data));
}

