// 認證方式（擇一）：
//   1. Authorization: Bearer <token>（curl / 程式化存取）
//   2. cookie bootstrap：開 `/?token=<token>` 驗過後 Set-Cookie，
//      前端同源 fetch/SSE 自動帶 cookie，status-app 完全不用改。
const STATUS_COOKIE = "status_token";

function tokenMatches(candidate: string | undefined | null, expected: string): boolean {
  if (!candidate) return false;
  const a = Buffer.from(candidate);
  const b = Buffer.from(expected);
  return a.length === b.length && timingSafeEqual(a, b);
}

function isAuthorized(req: IncomingMessage, apiToken: string): boolean {
  if (!apiToken) return true;
  const auth = req.headers.authorization;
  if (auth?.startsWith("Bearer ") && tokenMatches(auth.slice(7).trim(), apiToken)) return true;
  const cookie = req.headers.cookie ?? "";
  const m = cookie.match(new RegExp(`(?:^|;\\s*)${STATUS_COOKIE}=([^;]*)`));
  if (m && tokenMatches(safeDecode(m[1]), apiToken)) return true;
  return false;
}

