// check-status-auth.mjs — STATUS_API_TOKEN 認證閘 smoke test
// BC-1: 未設 token 時 /api/* 不需認證（向後相容）
// BC-2: 設 token 後無憑證的 /api/* 一律 401
// BC-3: Authorization: Bearer <token> 放行
// BC-4: `/?token=<token>` 發 HttpOnly cookie，cookie 放行後續 /api/*
// BC-5: 錯誤 token（bearer / cookie / query）一律拒絕
import assert from "node:assert";

const PORT = 3899;
let pass = 0, fail = 0;
function check(name, cond) {
  if (cond) { pass++; console.log(`PASS  ${name}`); }
  else { fail++; console.error(`FAIL  ${name}`); }
}

async function req(path, headers = {}) {
  const res = await fetch(`http://127.0.0.1:${PORT}${path}`, { headers });
  return res;
}

// ─── Phase 1: no token configured ───────────────────────────────────────────
delete process.env.STATUS_API_TOKEN;
const { startStatusServer, stopStatusServer } = await import("../dist/status-server.js");
startStatusServer(PORT);
await new Promise((r) => setTimeout(r, 200));

{
  const res = await req("/api/status");
  check("BC-1 no token configured → /api/status 200", res.status === 200);
}

// token 是每 request 讀 process.env，不用重啟 server
// ─── Phase 2: token configured ──────────────────────────────────────────────
process.env.STATUS_API_TOKEN = "s3cret-token";

{
  const res = await req("/api/status");
  check("BC-2 bare request → 401", res.status === 401);
}
{
  const res = await req("/api/status", { Authorization: "Bearer s3cret-token" });
  check("BC-3 correct bearer → 200", res.status === 200);
}
{
  const res = await req("/api/status", { Authorization: "Bearer wrong" });
  check("BC-5a wrong bearer → 401", res.status === 401);
}
{
  const res = await req("/?token=s3cret-token");
  const setCookie = res.headers.get("set-cookie") ?? "";
  check("BC-4a /?token=正確 → Set-Cookie 含 HttpOnly", /status_token=/.test(setCookie) && /HttpOnly/i.test(setCookie));
  const cookie = setCookie.split(";")[0];
  const res2 = await req("/api/status", { Cookie: cookie });
  check("BC-4b cookie 放行 /api/* → 200", res2.status === 200);
}
{
  const res = await req("/?token=wrong");
  check("BC-5b /?token=錯誤 → 無 Set-Cookie", !(res.headers.get("set-cookie") ?? "").includes("status_token"));
  const res2 = await req("/api/status", { Cookie: "status_token=wrong" });
  check("BC-5c 錯誤 cookie → 401", res2.status === 401);
}
{
  // 靜態頁不設防（HTML 無資料），只有 /api/* 才要憑證
  const res = await req("/");
  check("BC-2b 靜態頁無 token 仍 200（HTML 不含資料）", res.status === 200);
}

