  const raw = (process.env.RELAY_ALLOWED_BOT_IDS ?? "").trim();
  if (!raw) return true;
  const entries = raw.split(",").map((s) => s.trim()).filter(Boolean);
  return entries.some((e) =>
    e === String(from.id) ||
    (!!from.username && e.replace(/^@/, "").toLowerCase() === from.username.toLowerCase()));
}

