const pendingContinuations = new Map<number, NodeJS.Timeout>();

export function cancelPendingContinuation(chatId: number): void {
  const h = pendingContinuations.get(chatId);
  if (h) {
    clearTimeout(h);
    pendingContinuations.delete(chatId);
  }
}

// ─── Deps interface — mutable state that lives in index.ts ───────────────────

export interface RunPromptDeps {
  bot: Bot;
  sessions: SessionManager;
  rateLimitedUntil: () => number;
  onRateLimitRecovery: (fn: () => void | Promise<void>) => () => void;
  queuePendingMessage: (chatId: number, text: string) => void;
  handleRestart: (ctx: Context, opts?: { reason?: string }) => Promise<void>;
  STREAM_EDIT_INTERVAL_MS: number;
  MEMORY_DIR: string;
  scheduler: Scheduler;
  scheduleStore: ScheduleStore;
}

let _deps: RunPromptDeps | null = null;

export function initRunPrompt(deps: RunPromptDeps): void {
  _deps = deps;
}

function deps(): RunPromptDeps {
  if (!_deps) throw new Error("runPrompt not initialized — call initRunPrompt first");
  return _deps;
}

// ─── Auto-wikilink post-processing ───────────────────────────────────────────

/** After a wiki page is written, scan it and inject [[wikilinks]] for known entities. */
function applyAutoWikilink(slug: string): void {
  const { MEMORY_DIR } = deps();
  for (const sub of ["queries", "concepts", "references", "lessons", "tasks"]) {
    const filePath = path.join(MEMORY_DIR, "wiki", sub, `${slug}.md`);
    if (existsSync(filePath)) {
      try {
        const content = readFileSync(filePath, "utf8");
        const linked = autoWikilink(content);
        if (linked !== content) {
          writeFileSync(filePath, linked, "utf8");
          console.log(`[auto-wikilink] injected links into wiki/${sub}/${slug}.md`);
        }
      } catch (err) {
        console.error(`[auto-wikilink] failed for ${slug}:`, err);
      }
      return;
    }
  }
}

// ─── Orphan turn flusher ──────────────────────────────────────────────────────
//
// Delivers agent output that arrived with NO active prompt turn — e.g. a
// Claude Code harness background sub-agent completes and re-invokes the agent
// via task-notification, producing an agent_message_chunk while runPrompt's
// request→response flush path isn't listening (see SPEC-orphan-turn-flusher).
//
// SessionManager buffers + debounces those chunks and calls this on quiescence
// (wired via sessions.onOrphanTurn in index.ts). This reuses the SAME reply
// transform (transformReplyTokens) + render/split helpers as the normal turn —
// there is deliberately NO second transform. Tokens that only make sense inside
// a live turn (GOAL_DONE / RESTART / CONTINUE / WIKI_QUERY / SKILL_PROPOSE /
// SPECIALIST_PROXY / relay*) are intentionally ignored here; user-facing tokens
// (text / SEND_FILE / ASK / SCHEDULE / STICKER) are delivered.
export async function flushOrphanTurn(session: ChatSession, rawText: string): Promise<void> {
  const { bot, rateLimitedUntil, queuePendingMessage, scheduler, scheduleStore } = deps();

