// check-cancel-race.mjs — cancel → 新 turn → 舊 prompt 晚 resolve 競態 smoke test
// 驗證 bf76ac3 的 _turnSeq turn token 守衛：
// BC-1: 被取消的舊 turn 在 prompt() 晚 resolve 後不做收尾（不發訊息、不 push history）
// BC-2: 舊 turn 的 finally 不覆寫新 turn 的 onUpdate / inflight
// BC-3: cancel 後無新 turn 的情境：晚 resolve 也不發訊息，inflight 維持 false
// BC-4: 新 turn 正常收尾（訊息照發、history 照 push）
import { mkdtempSync, rmSync } from "node:fs";
import { tmpdir } from "node:os";
import path from "node:path";

const tempDir = mkdtempSync(path.join(tmpdir(), "cancel-race-"));
process.env.MEMORY_DIR = tempDir;
process.env.TG_DRAFT_ENABLED = "0"; // 走 placeholder 路徑，行為可預測

const { SessionManager } = await import("../dist/sessionManager.js");
const { initRunPrompt, runPrompt } = await import("../dist/run-prompt.js");

let pass = 0, fail = 0;
function check(name, cond, extra = "") {
  if (cond) { pass++; console.log(`PASS  ${name}`); }
  else { fail++; console.error(`FAIL  ${name}${extra ? ` — ${extra}` : ""}`); }
}

// ─── Fakes ───────────────────────────────────────────────────────────────────
const apiCalls = [];
const fakeApi = new Proxy({}, {
  get: (_t, prop) => {
    if (prop === "raw") return new Proxy({}, { get: () => async () => ({ ok: true }) });
    return async (...args) => {
      apiCalls.push({ method: String(prop), args });
      return { message_id: 1000 + apiCalls.length };
    };
  },
});
const fakeBot = { api: fakeApi, token: "fake" };

function makeFakeClient() {
  const c = {
    isClosed: false,
    _resolve: null,
    prompt() {
      return new Promise((resolve) => { c._resolve = resolve; });
    },
    cancel() {},
    async close() { c.isClosed = true; },
    on() {}, removeListener() {},
  };
  return c;
}

function makeSession(chatId, client) {
  return {
    chatId, client, sessionId: "s1", activeProvider: "acp",
    buffer: "", thinkingBuffer: undefined, toolLog: [], toolTimeline: [],
    stderrTail: "", history: [], charsIn: 0, charsOut: 0,
    memoryPreamble: "", preambleInjected: true,
    preambleBreakdown: { total: 0 },
    inflight: false, lastUsed: Date.now(),
    _pendingMetaQueue: [], _consecutiveToolFails: 0,
  };
}

const mgr = new SessionManager();
initRunPrompt({
  bot: fakeBot,
  sessions: mgr,
  rateLimitedUntil: () => 0,
  onRateLimitRecovery: () => () => {},
  queuePendingMessage: () => {},
  handleRestart: async () => {},
  STREAM_EDIT_INTERVAL_MS: 60_000,
  MEMORY_DIR: tempDir,
  scheduler: {},
  scheduleStore: {},
});

function makeCtx(chatId) {
  return {
    chat: { id: chatId, type: "private" },
    from: { id: 42 },
    message: { message_id: 1, date: 0, chat: { id: chatId, type: "private" } },
    api: fakeApi,
    reply: async (text, extra) => {
      apiCalls.push({ method: "ctx.reply", args: [text, extra] });
      return { message_id: 2000 + apiCalls.length, chat: { id: chatId } };
    },
  };
}

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

// ─── Scenario 1: cancel → 新 turn 接管 → 舊 prompt 晚 resolve ────────────────
{
  const chatId = 111;
  const clientA = makeFakeClient();
  const session = makeSession(chatId, clientA);
  mgr["sessions"].set(chatId, session);

  const turnA = runPrompt(makeCtx(chatId), session, "turn A prompt");
  await sleep(150); // 等 turn A 走到 await client.prompt()

  mgr.cancel(chatId); // 樂觀釋放：inflight=false, _cancelledTurn=true
  check("S1-pre cancel 後 inflight=false", session.inflight === false);

  // 新 turn 接管（同一 session 物件，換一個 client promise）
  const clientB = makeFakeClient();
  session.client = clientB;
  const turnB = runPrompt(makeCtx(chatId), session, "turn B prompt");
  await sleep(150);
  check("S1-pre turn B 已持有 session（inflight=true）", session.inflight === true);
  const onUpdateB = session.onUpdate;
  check("S1-pre turn B 已註冊 onUpdate", typeof onUpdateB === "function");

  // 模擬 turn B 的 streaming 內容進到共享 buffer
  session.buffer = "BUFFER_OWNED_BY_B";

  // 舊 turn A 的 prompt 這時才 resolve（cancelled）
  const callsBefore = apiCalls.length;
  clientA._resolve({ stopReason: "cancelled" });
  await turnA;
  await sleep(100);

  const aSends = apiCalls.slice(callsBefore).filter((c) =>
    ["sendMessage", "ctx.reply", "editMessageText"].includes(c.method));
  check("BC-1 舊 turn 晚 resolve 不發任何訊息", aSends.length === 0,
    `sent: ${JSON.stringify(aSends.map((c) => c.method))}`);
  check("BC-1b 舊 turn 不 push history", session.history.filter((h) => h.role === "assistant").length === 0);
  check("BC-2a 舊 turn finally 不清新 turn 的 onUpdate", session.onUpdate === onUpdateB);
  check("BC-2b 舊 turn finally 不動新 turn 的 inflight", session.inflight === true);

  // turn B 正常結束
  clientB._resolve({ stopReason: "end_turn" });
  await turnB;
  await sleep(100);
  check("BC-4a 新 turn 正常送出 final render",
    apiCalls.some((c) => ["sendMessage", "ctx.reply", "editMessageText"].includes(c.method) &&
      JSON.stringify(c.args).includes("BUFFER_OWNED_BY_B")));
  check("BC-4b 新 turn push history", session.history.filter((h) => h.role === "assistant").length === 1);
  check("BC-4c 新 turn finally 釋放 inflight", session.inflight === false);
}

// ─── Scenario 2: cancel 後無新 turn，舊 prompt 晚 resolve ────────────────────
{
  const chatId = 222;
  const clientA = makeFakeClient();
  const session = makeSession(chatId, clientA);
  mgr["sessions"].set(chatId, session);

  const turnA = runPrompt(makeCtx(chatId), session, "turn A prompt");
  await sleep(150);
  mgr.cancel(chatId);
  session.buffer = "ABANDONED_OUTPUT";

  const callsBefore = apiCalls.length;
  clientA._resolve({ stopReason: "cancelled" });
  await turnA;
  await sleep(100);

  const aSends = apiCalls.slice(callsBefore).filter((c) =>
    ["sendMessage", "ctx.reply", "editMessageText"].includes(c.method));
  check("BC-3a cancel 後（無新 turn）晚 resolve 不發訊息", aSends.length === 0,
    `sent: ${JSON.stringify(aSends.map((c) => c.method))}`);
  check("BC-3b inflight 維持 false", session.inflight === false);
  check("BC-3c 不 push history", session.history.filter((h) => h.role === "assistant").length === 0);
}

rmSync(tempDir, { recursive: true, force: true });
console.log(`\n═══ 結果：${pass} passed, ${fail} failed ═══`);
process.exit(fail === 0 ? 0 : 1);

