stripped = stripped.replace(ASK_RE, (match, inner: string) => {
  const entry = parseAskInner(inner);
  if (!entry) return match;
  if (seenAskIds.has(entry.questionId)) {
    const idx = askTokens.findIndex((a) => a.questionId === entry.questionId);
    if (idx >= 0) askTokens.splice(idx, 1);
  }
  seenAskIds.add(entry.questionId);
  askTokens.push(entry);
  return "";
});

