// Streaming UX helper: hide a trailing unterminated token opener.
// ───────────────────────────────────────────────────────────────────────
// When the agent is mid-write on a token like `<<GOAL_DONE:reason still
// being typed…`, transform() can't match the token (no closing `>>`)
// and leaves the opener visible in the output text. The user then sees
// `<<GOAL_DONE:reason still…` flicker in the placeholder until the
// agent emits `>>` — or worse, sees it frozen if the stream ends
// mid-token (final render also inherits the raw opener).
//
// This helper finds the LAST known-prefix opener in `text` that has no
// matching `>>` after it, and replaces the span from that opener to EOF
// with `…`. Only unterminated openers are trimmed; fully-terminated
// tokens (malformed or not) are left alone because they've already been
// decided by transform()'s extractors or kept as literal text.
//
// Called from transform()'s tail so both streaming frames and the final
// render get the same treatment. Exported for unit testing.
export function hideTrailingUnterminatedToken(text: string): string {
  const openerRe = /<<(?:GOAL_DONE|SKILL_USED|SKILL_PROPOSE|ASK|SCHEDULE|SEND_FILE|STICKER|WIKI_QUERY):|<<RESTART(?::|>?$)/g;
  let lastOpener = -1;
  for (;;) {
    const m = openerRe.exec(text);
    if (!m) break;
    lastOpener = m.index;
  }
  if (lastOpener < 0) return text;
  const tail = text.slice(lastOpener);
  if (tail.includes(">>")) return text; // fully-terminated — leave it
  return text.slice(0, lastOpener).replace(/\s+$/, "") + "\n…";
}

// ───────────────────────────────────────────────────────────────────────
// Thin per-token helpers — kept for callers that don't want the full
// `transform()` (e.g. replyWithAsk in index.ts only needs ASK parsing).
// These are all backed by `transform()` so behavior stays uniform.
// ───────────────────────────────────────────────────────────────────────

export function extractSendFileTokens(text: string): {
  text: string;
  paths: string[];
} {
  const r = transform(text, null);
  return { text: r.text, paths: r.sendFiles };
}

export function extractAskTokens(text: string): {
  text: string;
  asks: AskEntry[];
} {
  const r = transform(text, null);
  return { text: r.text, asks: r.askTokens };
}

