// ─── Dedup for "both" mode ─────────────────────────────────────────────────
const recentHashes = new Set<string>();
const DEDUP_TTL_MS = 10_000;

function dedupKey(from: string, text: string): string {
  // Simple hash: first 100 chars of text + sender
  return `${from}:${text.slice(0, 100)}`;
}

/** Returns true if this message is a duplicate (already seen recently). */
export function isDuplicate(from: string, text: string): boolean {
  const key = dedupKey(from, text);
  if (recentHashes.has(key)) return true;
  recentHashes.add(key);
  setTimeout(() => recentHashes.delete(key), DEDUP_TTL_MS);
  return false;
}

// ─── Telegram bot-to-bot incoming handler ──────────────────────────────────
const RELAY_PREFIX_RE = /^\[RELAY:([^\]]+)\]\s*/;

export interface ParsedBotRelay {
  from: string;
  text: string;
}

/** Parse an incoming bot message. Returns null if not a relay message. */
export function parseBotRelayMessage(rawText: string): ParsedBotRelay | null {
  const m = RELAY_PREFIX_RE.exec(rawText);
  if (!m) return null;
  return { from: m[1], text: rawText.slice(m[0].length) };
}

/** Get the registered incoming handler (set by startRelayPoller). */
export function getRelayHandler(): ((msg: RelayMessage) => void) | null {
  return onIncoming;
}

