const STICKER_AUTO_THRESHOLD = 0.65;
const STICKER_AUTO_MAX_REPLY_LEN = 150;
let emotionVectors: Map<string, Float32Array> | null = null;

export async function autoSelectSticker(reply: string): Promise<string | null> {
  if (reply.length > STICKER_AUTO_MAX_REPLY_LEN || reply.length < 5) return null;
  if (!emotionVectors) {
    emotionVectors = new Map();
    for (const [emotion, repr] of Object.entries(EMOTION_REPRS)) {
      const vec = await embedText(repr);
      if (vec) emotionVectors.set(emotion, vec);
    }
  }
  const queryVec = await embedText(reply);
  if (!queryVec) return null;
  let best = "";
  let bestScore = 0;
  for (const [emotion, vec] of emotionVectors) {
    const score = cosineSim(queryVec, vec);
    if (score > bestScore) { bestScore = score; best = emotion; }
  }
  return bestScore >= STICKER_AUTO_THRESHOLD ? best : null;
}

