file.content:
  const spawned = await spawnEphemeral(entry, userId);
  instanceId = spawned.instanceId;
  const inst = spawned.inst;

  const updateHandler = (u: SessionUpdate) => {
    const up = u.update;
    if (up.sessionUpdate === "agent_message_chunk") {
      const content = up.content as { type?: string; text?: string } | undefined;
      if (content?.type === "text" && typeof content.text === "string") output += content.text;
    }
  };
  inst.client.on("update", updateHandler);
  try {
    await Promise.race([
      inst.client.prompt(prompt),
      new Promise<never>((_, reject) => setTimeout(() => reject(new Error("timeout")), timeoutMs)),
    ]);
  } finally {
    inst.client.removeListener("update", updateHandler);
  }
  const text = output.trim().slice(0, OPINION_MAX_CHARS) || "（無回覆）";
  return { name: refName, status: "ok", text };
} catch (err: any) {
  const msg = String(err?.message ?? err);
  const partial = output.trim().slice(0, OPINION_MAX_CHARS);
  if (msg.includes("timeout")) {
    // Timeout with partial output is still a usable opinion.
    if (partial.length > 100) return { name: refName, status: "ok", text: partial + "\n…（timeout 截斷）" };
    return { name: refName, status: "timeout", text: "（逾時未回覆）" };
  }

