/**
 * Promise.race + timeout，settle 後一定 clearTimeout。
 * 裸寫 race 的 timeout timer 會存活到期滿（specialist 預設 30 分鐘/顆、
 * 每 turn 新增一顆），累積持有 closure。reject 訊息固定 "timeout"——
 * 呼叫端以 msg.includes("timeout") 分類，勿改字面。
 */
export async function raceWithTimeout<T>(p: Promise<T>, timeoutMs: number): Promise<T> {
  let timer: NodeJS.Timeout | undefined;
  try {
    return await Promise.race([
      p,
      new Promise<never>((_, reject) => {
        timer = setTimeout(() => reject(new Error("timeout")), timeoutMs);
      }),
    ]);
  } finally {
    if (timer) clearTimeout(timer);
  }
}
EOF
