/**
 * Pet WebSocket Server — pushes agent state events to the desktop pet app.
 * Protocol: ws://127.0.0.1:{PET_PORT} (default 38470)
 * Bridge is the WS server; pet app connects as client.
 */
// Lazy-loaded: ws is optional — pet feature degrades gracefully if missing
let WebSocketServer: any;
let WebSocket: any;
let wsAvailable = false;
try {
  const ws = await import("ws");
  WebSocketServer = ws.WebSocketServer;
  WebSocket = ws.WebSocket;
  wsAvailable = true;
} catch {
  console.warn("[pet] 'ws' package not installed — pet feature disabled");
}

export type PetState = "idle" | "thinking" | "tool" | "streaming" | "done" | "error";

export interface PetEvent {
  type: "state" | "reply";
  state?: PetState;
  text?: string;
  animation?: string;
  progress?: number;
  ttl_ms?: number;
}

const PORT = Number(process.env.PET_PORT ?? "38470");
const ENABLED = (() => {
  const raw = (process.env.PET_ENABLED ?? "0").trim().toLowerCase();
  return raw === "1" || raw === "true" || raw === "yes";
})();

let wss: any = null;
const clients = new Set<any>();
let idleTimer: NodeJS.Timeout | null = null;
const IDLE_DELAY_MS = 5 * 60 * 1000; // 5 min no activity → idle

export function startPetServer(): void {
  if (!ENABLED || !wsAvailable) return;
  wss = new WebSocketServer({ port: PORT, host: "127.0.0.1" });
  wss.on("connection", (ws: any) => {
    clients.add(ws);
    ws.on("close", () => clients.delete(ws));
    ws.on("error", () => clients.delete(ws));
    ws.on("message", (raw: any) => {
      try {
        const msg = JSON.parse(raw.toString());
        if (msg.type === "chat" && typeof msg.text === "string" && chatHandler) {
          chatHandler(msg.text);
        }
      } catch { /* ignore malformed */ }
    });
  });
  console.log(`[pet] WS server listening on ws://127.0.0.1:${PORT}`);
}

type PetChatHandler = (text: string) => void;
let chatHandler: PetChatHandler | null = null;
export function onPetChat(handler: PetChatHandler): void {
  chatHandler = handler;
}

export function petEmit(event: PetEvent): void {
  if (!wsAvailable || !wss || clients.size === 0) return;
  const msg = JSON.stringify(event);
  for (const ws of clients) {
    if (ws.readyState === WebSocket.OPEN) ws.send(msg);
  }
  resetIdleTimer();
}

/** Convenience: emit a state change */
export function petState(state: PetState, text?: string): void {
  petEmit({ type: "state", state, ...(text ? { text } : {}) });
}

function resetIdleTimer(): void {
  if (idleTimer) clearTimeout(idleTimer);
  idleTimer = setTimeout(() => petState("idle"), IDLE_DELAY_MS);
  idleTimer.unref?.();
}

export function stopPetServer(): void {
  if (idleTimer) clearTimeout(idleTimer);
  wss?.close();
  wss = null;
  clients.clear();
}

