export function buildRelayDelegationPrompt(from: string, d: DelegatePayload, attachmentPath?: string): string {
  return (
    `[Relay Delegation from "${from}" — id: ${d.id}]\n` +
    `你收到一個任務委派，請完成後回傳結果。\n` +
    `目標：${d.goal}\n` +
    (d.context ? `背景：${d.context}\n` : "") +
    (attachmentPath ? `參考檔案：${attachmentPath}\n` : "") +
    `如果任務產出了檔案（圖片等），請用 <<RELAY_FILE:${from}|絕對路徑>> 傳回給委派方，再發 RELAY_RESULT。\n` +
    `完成時請在回覆中加入：<<RELAY_RESULT:${from}|{"id":"${d.id}","status":"done","summary":"...你的摘要..."}>>\n` +
    `若無法完成：<<RELAY_RESULT:${from}|{"id":"${d.id}","status":"failed","summary":"...原因..."}>>\n` +
    `不要加 RELAY_DONE，RELAY_RESULT 會自動結束對話。`
  );
}

function injectRelayTaskNoticeToOwner(
  bot: Bot,
  ownerChatId: number,
  from: string,
  prompt: string,
  context: string,
): void {
  if (!ownerChatId) return;
  const { runPrompt, sessions } = deps();
  const fakeCtx = {
    chat: { id: ownerChatId, type: "private" as const },
    from: { id: ownerChatId, is_bot: false, first_name: from },
    message: { message_id: 0, date: 0, chat: { id: ownerChatId, type: "private" as const }, text: prompt },
    api: bot.api,
    reply: (text: string, extra?: any) => bot.api.sendMessage(ownerChatId, text, extra),
  } as unknown as Context;
  sessions.get(ownerChatId, ownerChatId).then((session) => {
    runPrompt(fakeCtx, session, prompt, { kind: "meta", silent: true }).catch((err) =>
      console.error(`[relay] owner task notice prompt failed (${context}):`, err));
  }).catch((err) => console.error(`[relay] owner task notice session get failed (${context}):`, err));
}


