/**
 * Artifact persistence — stores structured outputs from specialist delegations.
 * Files live at ${MEMORY_DIR}/artifacts/<date>_<taskId>_<specialist>_<slug>.json
 */
import { mkdir, writeFile } from "node:fs/promises";
import { existsSync, mkdirSync, writeFileSync, readFileSync, readdirSync, unlinkSync } from "node:fs";
import path from "node:path";
import { config } from "./config.js";
import { onSpecialistDone } from "./specialist-memory.js";

// ─── Types ─────────────────────────────────────────────────────────────────

export interface ArtifactOutput {
  type: string;       // e.g. "finding", "code_change", "recommendation"
  content: string;
}

export interface Artifact {
  id: string;
  specialist: string;
  task: string;
  created: string;    // ISO
  status: "done" | "partial" | "timeout" | "failed";
  summary: string;
  outputs: ArtifactOutput[];
  files_modified: string[];
  tags: string[];
}

// ─── JSON extraction from specialist raw output ────────────────────────────

const ARTIFACT_FENCE_RE = /```(?:json)?\s*\n(\{[\s\S]*?"type"\s*:\s*"artifact"[\s\S]*?\})\s*\n```/i;
const ARTIFACT_BARE_RE = /(\{[\s\S]*?"type"\s*:\s*"artifact"[\s\S]*?\})\s*$/;

/**
 * Try to extract an artifact JSON block from specialist output.
 * Returns parsed artifact fields or undefined if not found/invalid.
 */
export function extractArtifact(rawOutput: string): Partial<Artifact> | undefined {
  if (!rawOutput) return undefined;

  // Try fenced first, then bare JSON at end
  const match = ARTIFACT_FENCE_RE.exec(rawOutput) ?? ARTIFACT_BARE_RE.exec(rawOutput);
  if (!match) return undefined;

  try {
    const obj = JSON.parse(match[1]);
    if (obj.type !== "artifact") return undefined;
    return {
      summary: typeof obj.summary === "string" ? obj.summary : undefined,
      outputs: Array.isArray(obj.outputs) ? obj.outputs : [],
      files_modified: Array.isArray(obj.files_modified) ? obj.files_modified : [],
      tags: Array.isArray(obj.tags) ? obj.tags : [],
    };
  } catch {
    return undefined;
  }
}

// ─── Persistence ───────────────────────────────────────────────────────────

function slugify(text: string): string {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9\u4e00-\u9fff]+/g, "-")
    .replace(/^-|-$/g, "")
    .slice(0, 40);
}

/**
 * Save an artifact to disk. Called after specialist dispatch completes.
 * If the specialist output contains a structured artifact block, merge it;
 * otherwise create a minimal artifact from the result payload.
 */
export async function saveArtifact(
  taskId: string,
  specialist: string,
  goal: string,
  status: "done" | "timeout" | "failed",
  summary: string,
  rawOutput: string,
): Promise<string | undefined> {
  // Only persist successful or partial results
  if (status === "failed" && !rawOutput) return undefined;

  const dir = path.join(config.memoryDir, "artifacts");
  await mkdir(dir, { recursive: true });

  const extracted = extractArtifact(rawOutput);
  const date = new Date().toISOString().slice(0, 10);
  const slug = slugify(goal);
  const filename = `${date}_${taskId}_${specialist}_${slug}.json`;

  const artifact: Artifact = {
    id: taskId,
    specialist,
    task: goal,
    created: new Date().toISOString(),
    status,
    summary: extracted?.summary ?? summary.slice(0, 500),
    outputs: extracted?.outputs ?? [],
    files_modified: extracted?.files_modified ?? [],
    tags: extracted?.tags ?? [],
  };

  const filePath = path.join(dir, filename);
  await writeFile(filePath, JSON.stringify(artifact, null, 2), "utf8");
  console.log(`[artifact] saved: ${filename}`);

  // Auto-ingest hook: if outputs are long enough, save as pending ingest
  const totalOutputChars = artifact.outputs.reduce((sum, o) => sum + (o.content?.length ?? 0), 0);
  if (totalOutputChars > 5000 && specialist === "researcher") {
    savePendingIngest(slug, artifact);
  }

  // Phase B+: persist specialist lessons (fire-and-forget)
  if (status === "done") {
    onSpecialistDone(specialist, goal, rawOutput).catch((e) =>
      console.warn(`[artifact] specialist-memory failed:`, e));
  }

  return filePath;
}

// ─── Pending Ingest (for PageIndex Phase 2) ────────────────────────────────

const PENDING_DIR = () => path.join(config.memoryDir, "indexes", ".pending");

interface PendingIngest {
  slug: string;
  title: string;
  source: string;
  content: string;
  created_at: string;
}

function savePendingIngest(slug: string, artifact: Artifact): void {
  try {
    const dir = PENDING_DIR();
    mkdirSync(dir, { recursive: true });
    const content = artifact.outputs.map((o) => `## ${o.type}\n\n${o.content}`).join("\n\n---\n\n");
    const pending: PendingIngest = {
      slug: `researcher-${slug}`.slice(0, 60),
      title: artifact.task.slice(0, 100),
      source: `artifact:${artifact.id}`,
      content,
      created_at: new Date().toISOString(),
    };
    const filename = `${pending.slug}.json`;
    writeFileSync(path.join(dir, filename), JSON.stringify(pending, null, 2), "utf8");
    console.log(`[artifact] pending ingest queued: ${filename}`);
  } catch (err) {
    console.error(`[artifact] pending ingest failed:`, err);
  }
}

/**
 * List pending ingests (for preamble hint to agent).
 */
export function listPendingIngests(): PendingIngest[] {
  const dir = PENDING_DIR();
  if (!existsSync(dir)) return [];
  try {
    return readdirSync(dir)
      .filter((f) => f.endsWith(".json"))
      .map((f) => JSON.parse(readFileSync(path.join(dir, f), "utf8")) as PendingIngest);
  } catch { return []; }
}
